function init(sampleRate) {
  const chorusBufLen = Math.ceil(sampleRate * 0.03);
  const voices = [];
  for (let v = 0; v < 4; v++) {
    voices.push({
      phase: 0,
      freq: 0,
      smoothFreq: 0,
      envPhase: 0,
      triggered: false,
      eorTriggered: false,
      currentEnv: 0,
      active: false
    });
  }
  return {
    sampleRate: sampleRate,
    phase: 0,
    envPhase: 0,
    currentEnv: 0,
    triggered: false,
    eorTriggered: false,
    lastTrigger: 0,
    noiseLP: 0,
    smoothFreq: 0,
    phase7th: 0,
    voices: voices,
    nextVoice: 0,
    mode: 0,
    lastModeBtn: false,
    chorusBufL: new Float32Array(chorusBufLen),
    chorusBufR: new Float32Array(chorusBufLen),
    chorusBufLen: chorusBufLen,
    chorusWritePos: 0,
    chorusLfoPhase: 0
  };
}

function czSawPhase(p, a) {
  const bp = 0.5 - a * 0.48;
  return p < bp ? (p / bp) * 0.5 : 0.5 + ((p - bp) / (1.0 - bp)) * 0.5;
}

function czSquarePhase(p, a) {
  const linger = a * 0.98;
  const trans = 1.0 - linger;
  if (p < 0.5) {
    const hp = p * 2.0;
    return hp < linger ? 0.0 : ((hp - linger) / trans) * 0.5;
  } else {
    const hp = (p - 0.5) * 2.0;
    return hp < linger ? 0.5 : 0.5 + ((hp - linger) / trans) * 0.5;
  }
}

function resRamp(p, a) {
  const resonance = 1.0 + a * 15.0;
  const resPhase = (p * resonance) % 1.0;
  const ampEnvelope = 1.0 - p;
  return Math.sin(2.0 * Math.PI * resPhase) * ampEnvelope;
}

function resTri(p, a) {
  const resonance = 1.0 + a * 15.0;
  const resPhase = (p * resonance) % 1.0;
  const ampEnvelope = p < 0.5 ? p * 2.0 : 2.0 - p * 2.0;
  return Math.sin(2.0 * Math.PI * resPhase) * ampEnvelope;
}

function generateSample(p, type, amount) {
  let dp;
  switch (type) {
    case 0: dp = czSawPhase(p, amount); break;
    case 1: dp = czSquarePhase(p, amount); break;
    case 2:
      const pw = 0.05 + 0.95 * (1.0 - amount);
      dp = p < (1.0 - pw) ? 0.0 : (p - (1.0 - pw)) / pw;
      break;
    case 3:
      const bp3 = 0.5 - amount * 0.48;
      dp = p < bp3 ? p / bp3 : 1.0 + (p - bp3) / (1.0 - bp3);
      break;
    case 4:
      const bp4 = 1.0 - amount * 0.48;
      if (p < 0.5) return Math.sin(2 * Math.PI * p + Math.PI/2);
      if (p < bp4) return Math.sin(2 * Math.PI * (0.5 + ((p-0.5)/(bp4-0.5))*0.5) + Math.PI/2);
      return 1.0;
    case 5: return resRamp(p, amount);
    case 6: return resTri(p, amount);
    default: return Math.sin(2.0 * Math.PI * p + Math.PI/2);
  }
  return Math.sin(2.0 * Math.PI * dp + Math.PI / 2.0);
}

// 2x oversampled waveform: evaluate at midpoint and endpoint, average
function generateOsc2x(phase, inc, type1, type2, amount) {
  let pMid = phase + inc * 0.5;
  if (pMid >= 1.0) pMid -= 1.0;
  let pEnd = phase + inc;
  if (pEnd >= 1.0) pEnd -= 1.0;
  const s1 = (generateSample(pMid, type1, amount) + generateSample(pEnd, type1, amount)) * 0.5;
  const s2 = (generateSample(pMid, type2, amount) + generateSample(pEnd, type2, amount)) * 0.5;
  return s1 + s2;
}

function readDelay(buf, writePos, delaySamples, bufLen) {
  const readPos = writePos - delaySamples;
  const idx = readPos < 0 ? readPos + bufLen : readPos;
  const i0 = Math.floor(idx);
  const frac = idx - i0;
  const i1 = (i0 + 1) % bufLen;
  return buf[i0] * (1 - frac) + buf[i1] * frac;
}

function process(state, inputs, outputs, params, buttons) {
  const blockSize = 128;
  const { L, R, Env, EOR, EOF } = outputs;
  const negEnv = outputs["-Env"];

  const triggerIn = inputs["Trigger"] || new Float32Array(blockSize);
  const voIn = inputs["VO"] || new Float32Array(blockSize);
  const dcwIn = inputs["DCW"] || new Float32Array(blockSize);

  const firstFunc = Math.floor((params.First ?? 0) * 7);
  const secondFunc = Math.floor((params.Second ?? 0) * 7);
  const dcwAtt = ((params.DCWAttenuverter ?? 0.5) - 0.5) * 2.0;
  const dcwOffset = params.DCWOffset ?? 0;
  // Attenuverter: 0 = -1, 0.5 = 0, 1 = +1
  const envAmt = ((params["Env Amount"] ?? 0.5) - 0.5) * 2.0;
  const voOffset = (params.VOOffset ?? 0) * 5;
  const fineIn = inputs.Fine || new Float32Array(blockSize);
  const ringIn = inputs["Ring"] || new Float32Array(blockSize);
  const leftInSig = inputs["LeftIn"] || new Float32Array(blockSize);
  const rightInSig = inputs["RightIn"] || new Float32Array(blockSize);
  const fineAtt = ((params.FineAttenuverter ?? 0.5)- 0.5)* 2.0;
  const fineOffset = params.FineOffset ?? 0;
  const attackParam = params.A ?? 0.1;
  const decayParam = params.D ?? 0.5;
  const noiseAmt = params.Noise ?? 0;
  const noiseColor = params.Color ?? 0.5;

  // Slide: 0 = instant, 1 = ~2s glide time
  // Use exponential curve so most of the knob range is usable
  const slideParam = params.Slide ?? 0;
  const slideTime = slideParam * slideParam * 2.0; // 0-2 seconds, quadratic taper
  const slideCoeff = slideTime < 0.001 ? 1.0 : 1.0 - Math.exp(-1.0 / (slideTime * state.sampleRate));

  // Mode button: detect rising edge to cycle 0->1->2->0
  const modeBtn = buttons.Mode || false;
  if (modeBtn && !state.lastModeBtn) {
    state.mode = (state.mode + 1) % 3;
  }
  state.lastModeBtn = modeBtn;

  const chorusOn = buttons.Chorus || false;
  const chorusLfoRate = 0.5 / state.sampleRate;
  const chorusMinDelay = state.sampleRate * 0.005;
  const chorusMaxDelay = state.sampleRate * 0.015;

  const aSamples = Math.max(1, Math.pow(attackParam, 2) * 2.0 * state.sampleRate);
  const dSamples = Math.max(1, Math.pow(decayParam, 2) * 5.0 * state.sampleRate);

  for (let i = 0; i < blockSize; i++) {
    const trig = triggerIn[i] > 2.5;
    const wasTrig = state.lastTrigger > 2.5;
    state.lastTrigger = triggerIn[i];

    const fineCV = fineIn ? fineIn[i] / 5.0 : 0;  // normalize ±5V to ±1
    const targetFreq = 65.406 * Math.pow(2, (voIn[i] || 0) + voOffset + fineOffset + (fineCV * fineAtt));

    let outputL = 0, outputR = 0;
    let envSum = 0;
    let eor = 0, eof = 0;

    const ringVal = ringIn[i] / 5.0;

    if (state.mode === 2) {
      // --- POLY MODE ---
      if (trig && !wasTrig) {
        const v = state.voices[state.nextVoice];
        v.freq = targetFreq;
        if (v.smoothFreq === 0) v.smoothFreq = targetFreq;
        v.triggered = true;
        v.envPhase = 0;
        v.eorTriggered = false;
        v.phase = 0;
        state.nextVoice = (state.nextVoice + 1) % 4;
      }

      for (let vi = 0; vi < 4; vi++) {
        const v = state.voices[vi];

        let linEnv = 0;
        if (v.triggered) {
          if (v.envPhase < aSamples) {
            linEnv = v.envPhase / aSamples;
          } else if (v.envPhase < aSamples + dSamples) {
            if (!v.eorTriggered) { eor = 5; v.eorTriggered = true; }
            linEnv = 1.0 - (v.envPhase - aSamples) / dSamples;
          } else {
            v.triggered = false;
            eof = 5;
          }
          v.envPhase++;
        }
        const vEnv = linEnv * linEnv;
        v.currentEnv = vEnv;
        envSum += vEnv;

        v.smoothFreq += slideCoeff * (v.freq - v.smoothFreq);
        const vInc = v.smoothFreq / state.sampleRate;

        const dcwCV = (dcwIn[i] / 5) * dcwAtt;
        const dcwMod = Math.max(0, Math.min(1, dcwOffset + (vEnv * envAmt) + dcwCV));
        const mix = generateOsc2x(v.phase, vInc, firstFunc, secondFunc, dcwMod);

        v.phase += vInc;
        if (v.phase >= 1.0) v.phase -= 1.0;

        // Ping-pong: even voices left, odd voices right
        const voiceOut = (mix * 0.4) * vEnv;
        if (vi % 2 === 0) {
          outputL += voiceOut;
        } else {
          outputR += voiceOut;
        }
      }
      outputL *= 0.35;
      outputR *= 0.35;

      const white = Math.random() * 2 - 1;
      const lpAlpha = Math.pow(1.0 - noiseColor, 3);
      state.noiseLP = state.noiseLP + lpAlpha * (white - state.noiseLP);
      const noiseSig = state.noiseLP * (1.0 + noiseColor * 2.0) * noiseAmt * 0.5;
      outputL += noiseSig;
      outputR += noiseSig;

    } else {
      // --- DRONE / MONO MODE ---
      if (trig && !wasTrig) {
        state.triggered = true;
        state.envPhase = 0;
        state.eorTriggered = false;
      }

      let linEnv = 0;
      if (state.triggered) {
        if (state.envPhase < aSamples) {
          linEnv = state.envPhase / aSamples;
        } else if (state.envPhase < aSamples + dSamples) {
          if (!state.eorTriggered) { eor = 5; state.eorTriggered = true; }
          linEnv = 1.0 - (state.envPhase - aSamples) / dSamples;
        } else {
          state.triggered = false;
          eof = 5;
        }
        state.envPhase++;
      }
      const snappyEnv = linEnv * linEnv;
      state.currentEnv = snappyEnv;
      envSum = snappyEnv;

      // Portamento
      if (state.smoothFreq === 0) state.smoothFreq = targetFreq;
      state.smoothFreq += slideCoeff * (targetFreq - state.smoothFreq);
      const inc = state.smoothFreq / state.sampleRate;

      const dcwCV = (dcwIn[i] / 5) * dcwAtt;
      const dcwMod = Math.max(0, Math.min(1, dcwOffset + (snappyEnv * envAmt) + dcwCV));

      // Left: base frequency
      const mixL = generateOsc2x(state.phase, inc, firstFunc, secondFunc, dcwMod);
      state.phase += inc;
      if (state.phase >= 1.0) state.phase -= 1.0;

      // Right: a 7th higher (7 semitones up)
      const inc7th = inc * 1.4983070768766815; // 2^(7/12)
      const mixR = generateOsc2x(state.phase7th, inc7th, firstFunc, secondFunc, dcwMod);
      state.phase7th += inc7th;
      if (state.phase7th >= 1.0) state.phase7th -= 1.0;

      const white = Math.random() * 2 - 1;
      const lpAlpha = Math.pow(1.0 - noiseColor, 3);
      state.noiseLP = state.noiseLP + lpAlpha * (white - state.noiseLP);
      const finalNoise = state.noiseLP * (1.0 + noiseColor * 2.0);

      const rawL = mixL * 0.4 + (finalNoise * noiseAmt);
      const rawR = mixR * 0.4 + (finalNoise * noiseAmt);

      if (state.mode === 1) {
        outputL = rawL * snappyEnv;
        outputR = rawR * snappyEnv;
      } else {
        outputL = rawL * 0.5;
        outputR = rawR * 0.5;
      }
    }

    // Ring modulation of external inputs
    outputL += leftInSig[i] * ringVal;
    outputR += rightInSig[i] * ringVal;

    // Chorus
    if (chorusOn) {
      const wp = state.chorusWritePos;
      state.chorusBufL[wp] = outputL;
      state.chorusBufR[wp] = outputR;

      const lfoL = Math.sin(2 * Math.PI * state.chorusLfoPhase);
      const lfoR = Math.sin(2 * Math.PI * state.chorusLfoPhase + Math.PI * 0.5);
      state.chorusLfoPhase += chorusLfoRate;
      if (state.chorusLfoPhase >= 1.0) state.chorusLfoPhase -= 1.0;

      const delayL = chorusMinDelay + (lfoL * 0.5 + 0.5) * (chorusMaxDelay - chorusMinDelay);
      const delayR = chorusMinDelay + (lfoR * 0.5 + 0.5) * (chorusMaxDelay - chorusMinDelay);

      const wetL = readDelay(state.chorusBufL, wp, delayL, state.chorusBufLen);
      const wetR = readDelay(state.chorusBufR, wp, delayR, state.chorusBufLen);

      state.chorusWritePos = (wp + 1) % state.chorusBufLen;

      L[i] = outputL * 0.5 + wetL * 0.5;
      R[i] = outputR * 0.5 + wetR * 0.5;
    } else {
      L[i] = outputL;
      R[i] = outputR;
    }

    const envOut = Math.min(envSum, 1.0) * 5.0;
    Env[i] = envOut;
    if (negEnv) negEnv[i] = -envOut;
    EOR[i] = eor;
    EOF[i] = eof;
  }
  return state;
}
